# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public class TicketService : ITicketService
{
    private readonly IDbContextFactory<EventBookingSystemDbContext> _contextFactory;

    public TicketService(IDbContextFactory<EventBookingSystemDbContext> contextFactory)
    {
        _contextFactory = contextFactory;
    }

    public async Task<bool> PurchaseTickets(int eventId, int userId, int quantity)
    {
        using (var context = _contextFactory.CreateDbContext())
        {
            // Get the relevant event and seats
            var evt = await context.Events.Include(e => e.Seats).FirstOrDefaultAsync(e => e.Id == eventId);
            if (evt == null) return false;

            // Check quantity is valid
            if (quantity <= 0 || quantity > evt.TotalSeats) return false;
            
            // Check availability of seats
            var availableSeats = evt.Seats.Where(s => !s.IsPurchased).Count();
            if (availableSeats < quantity) return false;

            // Update inventory and record purchase
            for (int i = 0; i < quantity; i++)
            {
                var seat = evt.Seats.FirstOrDefault(s => !s.IsPurchased);
                if (seat == null) return false;
                
                // Record ticket purchase
                await context.TicketPurchases.AddAsync(new TicketPurchase { EventId = eventId, UserId = userId, SeatId = seat.Id });
                seat.IsPurchased = true;
            }
            
            await context.SaveChangesAsync();
        }
        
        return true;
    }
}